LEGACY_HTML = True  # 既存HTMLを保持（再アセンブル禁止）
TITLE = 'BMI・体型管理トラッカー｜標準体重・目標体重を無料計算＆記録'
DESCRIPTION = 'BMIを無料で計算し、標準体重・目標体重・体脂肪率の目安を表示。体重の毎日記録と推移グラフ、BMI別のダイエット・健康アドバイスも。スマホに保存されるので登録不要。'
JS_CODE = 'const STORE_KEY = \'bmi_records_v1\';\nconst PROFILE_KEY = \'bmi_profile_v1\';\nlet gender = \'male\';\nlet goalBmi = 21;\n\nconst BMI_RANGES = [\n    { max: 18.5, label: \'低体重\', color: \'#3b82f6\', bg: \'linear-gradient(135deg,#1d4ed8,#3b82f6)\' },\n    { max: 25,   label: \'普通体重\', color: \'#16a34a\', bg: \'linear-gradient(135deg,#14532d,#16a34a)\' },\n    { max: 30,   label: \'肥満（1度）\', color: \'#d97706\', bg: \'linear-gradient(135deg,#92400e,#d97706)\' },\n    { max: 35,   label: \'肥満（2度）\', color: \'#dc2626\', bg: \'linear-gradient(135deg,#991b1b,#dc2626)\' },\n    { max: 40,   label: \'肥満（3度）\', color: \'#9333ea\', bg: \'linear-gradient(135deg,#6b21a8,#9333ea)\' },\n    { max: 999,  label: \'肥満（4度）\', color: \'#7c3aed\', bg: \'linear-gradient(135deg,#4c1d95,#7c3aed)\' },\n];\n\nfunction getBmiRange(bmi) {\n    return BMI_RANGES.find(r => bmi < r.max) || BMI_RANGES[BMI_RANGES.length-1];\n}\n\n// 体脂肪率推定（Deurenberg式の簡易版）\nfunction estimateBodyFat(bmi, age, isMale) {\n    const ageNum = { teens: 17, \'20s\': 28, \'40s\': 48, \'60s\': 68 }[age] || 28;\n    const sex = isMale ? 1 : 0;\n    return (1.20 * bmi) + (0.23 * ageNum) - (10.8 * sex) - 5.4;\n}\n\nfunction selectGender(g, el) {\n    gender = g;\n    document.querySelectorAll(\'.gender-btn\').forEach(b => { b.classList.remove(\'selected\'); });\n    el.classList.add(\'selected\');\n    updateCalc();\n}\n\nfunction setGoalBmi(bmi, el) {\n    goalBmi = bmi;\n    document.querySelectorAll(\'.goal-btn\').forEach(b => {\n        b.style.borderColor=\'#fed7aa\'; b.style.background=\'#fff\'; b.style.color=\'#64748b\';\n    });\n    el.style.borderColor=\'#ea580c\'; el.style.background=\'#fff7ed\'; el.style.color=\'#ea580c\';\n    updateCalc();\n}\n\nfunction updateCalc() {\n    const h = parseInt(document.getElementById(\'height\').value);\n    const w = parseFloat(document.getElementById(\'weight\').value);\n    const age = document.getElementById(\'age\').value;\n    const hm = h / 100;\n\n    document.getElementById(\'height-disp\').textContent = h + \' cm\';\n    document.getElementById(\'weight-disp\').textContent = w.toFixed(1) + \' kg\';\n\n    const bmi = w / (hm * hm);\n    const range = getBmiRange(bmi);\n    const stdWeight = Math.round(hm * hm * 22 * 10) / 10;\n    const idealWeight = Math.round(hm * hm * 21 * 10) / 10;\n    const bodyFat = Math.round(estimateBodyFat(bmi, age, gender === \'male\') * 10) / 10;\n    const diff = Math.round((w - stdWeight) * 10) / 10;\n\n    // BMIポインター位置（BMI10〜45の範囲でマッピング）\n    const pct = Math.max(0, Math.min(100, (bmi - 10) / 35 * 100));\n\n    document.getElementById(\'calc-result\').innerHTML = `\n        <div class="result-hero" style="background:${range.bg};">\n            <div style="font-size:0.82em;opacity:0.9;">あなたのBMI</div>\n            <div class="bmi-val">${bmi.toFixed(1)}</div>\n            <div class="bmi-label">${range.label}</div>\n            <div class="sub">${h}cm・${w}kg</div>\n        </div>\n        <div class="card" style="margin-bottom:14px;">\n            <p style="font-size:0.75em;color:#64748b;margin-bottom:6px;">BMIゾーン</p>\n            <div class="bmi-meter">\n                <div class="bmi-bar"><div class="bmi-pointer" style="left:${pct}%;"></div></div>\n                <div class="bmi-labels"><span>低体重<br>〜18.5</span><span>普通<br>25未満</span><span>肥満1<br>〜30</span><span>肥満2<br>〜35</span><span>肥満3+</span></div>\n            </div>\n        </div>\n        <div class="result-grid">\n            <div class="result-box green"><div class="val">${stdWeight}kg</div><div class="lbl">標準体重（BMI22）</div></div>\n            <div class="result-box orange"><div class="val">${diff >= 0 ? \'+\' : \'\'}${diff}kg</div><div class="lbl">標準体重との差</div></div>\n            <div class="result-box blue"><div class="val">${idealWeight}kg</div><div class="lbl">理想体重（BMI21）</div></div>\n            <div class="result-box ${bodyFat > (gender===\'male\' ? 25 : 35) ? \'red\' : \'green\'}"><div class="val">${bodyFat}%</div><div class="lbl">体脂肪率（推定）</div></div>\n        </div>`;\n\n    // 目標体重\n    const goalWeight = Math.round(hm * hm * goalBmi * 10) / 10;\n    const goalDiff = Math.round((w - goalWeight) * 10) / 1'
MAIN_HTML = '<div><button class="btn">開始する</button></div>'
